#include <stdio.h>
#include <stdint.h>
int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        long long X, Y; scanf("%lld %lld", &X, &Y);
        long long N;
        if (X==1 && Y==1) N = 1;
        else if (X==1) N = Y-1;
        else if (Y==1) N = X-1;
        else N = X*Y - X - Y;
        printf("%lld\n", N);
    }
    return 0;
}

